import os
import json
import pickle
import numpy as np
from pathlib import Path
from typing import Optional
from datetime import datetime

import face_recognition
from fastapi import FastAPI, UploadFile, File, HTTPException
from fastapi.responses import JSONResponse
from pydantic import BaseModel
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
from PIL import Image
import io
import uvicorn

# Configuration
MODEL_DIR = Path("models")
TRAINING_DIR = Path("training_data")
MODEL_PATH = MODEL_DIR / "face_recognition_model.pkl"
ENCODER_PATH = MODEL_DIR / "label_encoder.pkl"
ENCODINGS_PATH = MODEL_DIR / "face_encodings.pkl"

MODEL_DIR.mkdir(exist_ok=True)
TRAINING_DIR.mkdir(exist_ok=True)

app = FastAPI(
    title="Office Facial Recognition Security System",
    description="Facial recognition API for office security. Train on employee photos and identify faces with confidence scores.",
    version="1.0.0"
)


class TrainingStatus(BaseModel):
    status: str
    total_employees: int
    total_images: int
    employees: list[str]
    trained_at: Optional[str] = None


class RecognitionResult(BaseModel):
    status: str
    faces_detected: int
    results: list[dict]
    timestamp: str


class FaceRecognitionSystem:
    def __init__(self):
        self.model: Optional[SVC] = None
        self.label_encoder: Optional[LabelEncoder] = None
        self.known_encodings: list = []
        self.known_labels: list = []
        self.is_trained: bool = False
        self.trained_at: Optional[str] = None
        self._load_model()

    def _load_model(self):
        """Load pre-trained model if available."""
        if MODEL_PATH.exists() and ENCODER_PATH.exists() and ENCODINGS_PATH.exists():
            try:
                with open(MODEL_PATH, "rb") as f:
                    self.model = pickle.load(f)
                with open(ENCODER_PATH, "rb") as f:
                    self.label_encoder = pickle.load(f)
                with open(ENCODINGS_PATH, "rb") as f:
                    data = pickle.load(f)
                    self.known_encodings = data["encodings"]
                    self.known_labels = data["labels"]
                    self.trained_at = data.get("trained_at")
                self.is_trained = True
                print(f"Model loaded successfully. {len(set(self.known_labels))} employees registered.")
            except Exception as e:
                print(f"Error loading model: {e}")
                self.is_trained = False

    def _save_model(self):
        """Save trained model to disk."""
        with open(MODEL_PATH, "wb") as f:
            pickle.dump(self.model, f)
        with open(ENCODER_PATH, "wb") as f:
            pickle.dump(self.label_encoder, f)
        with open(ENCODINGS_PATH, "wb") as f:
            pickle.dump({
                "encodings": self.known_encodings,
                "labels": self.known_labels,
                "trained_at": self.trained_at
            }, f)

    def add_employee_photo(self, employee_id: str, image_data: bytes) -> dict:
        """Add a training photo for an employee."""
        employee_dir = TRAINING_DIR / employee_id
        employee_dir.mkdir(exist_ok=True)

        # Load and validate image
        try:
            image = Image.open(io.BytesIO(image_data))
            image_np = np.array(image)
        except Exception as e:
            raise ValueError(f"Invalid image data: {e}")

        # Detect faces
        face_locations = face_recognition.face_locations(image_np, model="hog")
        if len(face_locations) == 0:
            raise ValueError("No face detected in the image.")
        if len(face_locations) > 1:
            raise ValueError(f"Multiple faces ({len(face_locations)}) detected. Please provide a photo with a single face.")

        # Get face encoding
        face_encodings = face_recognition.face_encodings(image_np, face_locations)
        if len(face_encodings) == 0:
            raise ValueError("Could not encode face features.")

        # Save image
        existing_photos = list(employee_dir.glob("*.jpg")) + list(employee_dir.glob("*.png"))
        photo_index = len(existing_photos) + 1
        photo_path = employee_dir / f"photo_{photo_index}.jpg"
        image.save(str(photo_path), "JPEG")

        return {
            "employee_id": employee_id,
            "photo_saved": str(photo_path),
            "photo_number": photo_index,
            "face_location": face_locations[0]
        }

    def train(self) -> dict:
        """Train the facial recognition model on all employee photos."""
        encodings = []
        labels = []
        employee_stats = {}

        # Scan training directory
        for employee_dir in TRAINING_DIR.iterdir():
            if not employee_dir.is_dir():
                continue

            employee_id = employee_dir.name
            photo_count = 0

            for photo_path in employee_dir.iterdir():
                if photo_path.suffix.lower() not in [".jpg", ".jpeg", ".png", ".bmp"]:
                    continue

                try:
                    image = face_recognition.load_image_file(str(photo_path))
                    face_locations = face_recognition.face_locations(image, model="hog")

                    if len(face_locations) != 1:
                        print(f"Skipping {photo_path}: {len(face_locations)} faces detected")
                        continue

                    face_encoding = face_recognition.face_encodings(image, face_locations)[0]
                    encodings.append(face_encoding)
                    labels.append(employee_id)
                    photo_count += 1
                except Exception as e:
                    print(f"Error processing {photo_path}: {e}")

            if photo_count > 0:
                employee_stats[employee_id] = photo_count

        if len(encodings) < 2:
            raise ValueError("Need at least 2 face encodings to train. Add more employee photos.")

        unique_labels = set(labels)
        if len(unique_labels) < 2:
            raise ValueError("Need at least 2 different employees to train the classifier.")

        # Encode labels
        self.label_encoder = LabelEncoder()
        encoded_labels = self.label_encoder.fit_transform(labels)

        # Train SVM with probability estimates
        self.model = SVC(
            kernel="rbf",
            probability=True,
            C=10.0,
            gamma="scale",
            class_weight="balanced"
        )
        self.model.fit(encodings, encoded_labels)

        # Store data
        self.known_encodings = encodings
        self.known_labels = labels
        self.is_trained = True
        self.trained_at = datetime.utcnow().isoformat()

        # Save model
        self._save_model()

        return {
            "status": "trained",
            "total_employees": len(employee_stats),
            "total_images": len(encodings),
            "employee_stats": employee_stats,
            "trained_at": self.trained_at
        }

    def recognize(self, image_data: bytes, unknown_threshold: float = 0.4) -> dict:
        """
        Recognize faces in an image and return confidence scores for all classes.
        """
        if not self.is_trained:
            raise ValueError("Model is not trained yet. Please train the model first.")

        # Load image
        try:
            image = Image.open(io.BytesIO(image_data))
            image_np = np.array(image)
        except Exception as e:
            raise ValueError(f"Invalid image data: {e}")

        # Detect faces
        face_locations = face_recognition.face_locations(image_np, model="hog")
        if len(face_locations) == 0:
            return {
                "faces_detected": 0,
                "results": [],
                "message": "No faces detected in the image."
            }

        # Get encodings for all detected faces
        face_encodings = face_recognition.face_encodings(image_np, face_locations)

        results = []
        class_names = list(self.label_encoder.classes_)

        for idx, (face_encoding, face_location) in enumerate(zip(face_encodings, face_locations)):
            # Get SVM probability distribution
            probabilities = self.model.predict_proba([face_encoding])[0]

            # Build probability distribution
            probability_distribution = {}
            for class_idx, class_name in enumerate(class_names):
                probability_distribution[class_name] = round(float(probabilities[class_idx]), 6)

            # Sort by probability descending
            sorted_distribution = dict(
                sorted(probability_distribution.items(), key=lambda x: x[1], reverse=True)
            )

            # Get best match
            best_match_idx = np.argmax(probabilities)
            best_match_confidence = float(probabilities[best_match_idx])
            best_match_name = class_names[best_match_idx]

            # Calculate face distances to all known encodings for the best match
            # Filter encodings for the best match employee
            best_match_indices = [
                i for i, label in enumerate(self.known_labels) if label == best_match_name
            ]
            best_match_encodings = [self.known_encodings[i] for i in best_match_indices]
            face_distances = face_recognition.face_distance(best_match_encodings, face_encoding)
            avg_distance = float(np.mean(face_distances))
            min_distance = float(np.min(face_distances))

            # Determine if the face is known or unknown
            is_known = best_match_confidence >= unknown_threshold

            # Compute distances to all employees
            distance_per_employee = {}
            for employee_id in class_names:
                emp_indices = [i for i, label in enumerate(self.known_labels) if label == employee_id]
                emp_encodings = [self.known_encodings[i] for i in emp_indices]
                emp_distances = face_recognition.face_distance(emp_encodings, face_encoding)
                distance_per_employee[employee_id] = {
                    "mean_distance": round(float(np.mean(emp_distances)), 6),
                    "min_distance": round(float(np.min(emp_distances)), 6),
                    "max_distance": round(float(np.max(emp_distances)), 6),
                    "num_reference_photos": len(emp_encodings)
                }

            # Sort distances by mean distance ascending
            sorted_distances = dict(
                sorted(distance_per_employee.items(), key=lambda x: x[1]["mean_distance"])
            )

            top, right, bottom, left = face_location
            result = {
                "face_index": idx,
                "face_location": {
                    "top": top,
                    "right": right,
                    "bottom": bottom,
                    "left": left
                },
                "identified_as": best_match_name if is_known else "UNKNOWN",
                "is_recognized": is_known,
                "confidence": round(best_match_confidence, 6),
                "recognition_threshold": unknown_threshold,
                "best_match": {
                    "employee_id": best_match_name,
                    "svm_confidence": round(best_match_confidence, 6),
                    "avg_face_distance": round(avg_distance, 6),
                    "min_face_distance": round(min_distance, 6),
                },
                "probability_distribution": sorted_distribution,
                "face_distances_per_employee": sorted_distances,
                "entropy": round(float(-np.sum(probabilities * np.log(probabilities + 1e-10))), 6),
                "top_k_matches": [
                    {"employee_id": k, "confidence": v}
                    for k, v in list(sorted_distribution.items())[:5]
                ]
            }
            results.append(result)

        return {
            "faces_detected": len(face_locations),
            "results": results
        }


# Initialize the system
face_system = FaceRecognitionSystem()


@app.get("/", tags=["Health"])
async def root():
    return {
        "service": "Office Facial Recognition Security System",
        "version": "1.0.0",
        "model_trained": face_system.is_trained,
        "trained_at": face_system.trained_at,
        "registered_employees": len(set(face_system.known_labels)) if face_system.is_trained else 0
    }


@app.get("/status", tags=["Health"])
async def status():
    employees = list(set(face_system.known_labels)) if face_system.known_labels else []
    return TrainingStatus(
        status="trained" if face_system.is_trained else "untrained",
        total_employees=len(employees),
        total_images=len(face_system.known_encodings),
        employees=sorted(employees),
        trained_at=face_system.trained_at
    )


@app.post("/employees/{employee_id}/photos", tags=["Training"])
async def upload_employee_photo(employee_id: str, file: UploadFile = File(...)):
    """Upload a training photo for an employee."""
    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image.")

    image_data = await file.read()

    try:
        result = face_system.add_employee_photo(employee_id, image_data)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    return JSONResponse(
        status_code=201,
        content={
            "status": "photo_added",
            "detail": result,
            "message": f"Photo added for employee '{employee_id}'. Remember to retrain the model."
        }
    )


@app.get("/employees", tags=["Training"])
async def list_employees():
    """List all registered employees and their photo counts."""
    employees = {}
    if TRAINING_DIR.exists():
        for employee_dir in sorted(TRAINING_DIR.iterdir()):
            if employee_dir.is_dir():
                photos = [
                    p for p in employee_dir.iterdir()
                    if p.suffix.lower() in [".jpg", ".jpeg", ".png", ".bmp"]
                ]
                employees[employee_dir.name] = {
                    "photo_count": len(photos),
                    "photos": [p.name for p in photos]
                }

    return {
        "total_employees": len(employees),
        "employees": employees
    }


@app.delete("/employees/{employee_id}", tags=["Training"])
async def delete_employee(employee_id: str):
    """Remove an employee and their photos from the training data."""
    employee_dir = TRAINING_DIR / employee_id
    if not employee_dir.exists():
        raise HTTPException(status_code=404, detail=f"Employee '{employee_id}' not found.")

    import shutil
    shutil.rmtree(employee_dir)

    return {
        "status": "deleted",
        "employee_id": employee_id,
        "message": "Remember to retrain the model."
    }


@app.post("/train", tags=["Training"])
async def train_model():
    """Train the facial recognition model on all employee photos."""
    try:
        result = face_system.train()
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    return JSONResponse(
        status_code=200,
        content={
            "status": "success",
            "detail": result,
            "message": "Model trained successfully."
        }
    )


@app.post("/recognize", tags=["Recognition"], response_model=RecognitionResult)
async def recognize_face(
    file: UploadFile = File(...),
    threshold: float = 0.4
):
    """
    Recognize faces in an uploaded image.

    Returns detailed probability distribution over all known employees
    with confidence scores, face distances, and entropy measures.

    - **file**: Image file containing one or more faces
    - **threshold**: Minimum confidence to consider a face as recognized (0.0-1.0)
    """
    if not face_system.is_trained:
        raise HTTPException(
            status_code=400,
            detail="Model is not trained. Upload employee photos and call /train first."
        )

    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image.")

    if not 0.0 <= threshold <= 1.0:
        raise HTTPException(status_code=400, detail="Threshold must be between 0.0 and 1.0.")

    image_data = await file.read()

    try:
        result = face_system.recognize(image_data, unknown_threshold=threshold)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    return RecognitionResult(
        status="success",
        faces_detected=result["faces_detected"],
        results=result["results"],
        timestamp=datetime.utcnow().isoformat()
    )


@app.post("/recognize/batch", tags=["Recognition"])
async def recognize_batch(
    files: list[UploadFile] = File(...),
    threshold: float = 0.4
):
    """
    Recognize faces in multiple images.
    Returns detailed results for each image.
    """
    if not face_system.is_trained:
        raise HTTPException(
            status_code=400,
            detail="Model is not trained. Upload employee photos and call /train first."
        )

    all_results = []
    for file in files:
        if not file.content_type or not file.content_type.startswith("image/"):
            all_results.append({
                "filename": file.filename,
                "status": "error",
                "detail": "Not an image file"
            })
            continue

        image_data = await file.read()
        try:
            result = face_system.recognize(image_data, unknown_threshold=threshold)
            all_results.append({
                "filename": file.filename,
                "status": "success",
                "faces_detected": result["faces_detected"],
                "results": result["results"]
            })
        except ValueError as e:
            all_results.append({
                "filename": file.filename,
                "status": "error",
                "detail": str(e)
            })

    return {
        "status": "success",
        "total_images": len(files),
        "batch_results": all_results,
        "timestamp": datetime.utcnow().isoformat()
    }


@app.post("/verify", tags=["Recognition"])
async def verify_employee(
    employee_id: str,
    file: UploadFile = File(...),
    threshold: float = 0.5
):
    """
    Verify if a face matches a specific employee.
    Returns True/False with confidence details.
    """
    if not face_system.is_trained:
        raise HTTPException(
            status_code=400,
            detail="Model is not trained."
        )

    known_employees = list(face_system.label_encoder.classes_)
    if employee_id not in known_employees:
        raise HTTPException(
            status_code=404,
            detail=f"Employee '{employee_id}' not found in trained model. Known employees: {known_employees}"
        )

    image_data = await file.read()

    try:
        result = face_system.recognize(image_data, unknown_threshold=threshold)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    if result["faces_detected"] == 0:
        return {
            "verified": False,
            "employee_id": employee_id,
            "reason": "No face detected in image",
            "timestamp": datetime.utcnow().isoformat()
        }

    if result["faces_detected"] > 1:
        return {
            "verified": False,
            "employee_id": employee_id,
            "reason": f"Multiple faces ({result['faces_detected']}) detected. Please provide single face image.",
            "timestamp": datetime.utcnow().isoformat()
        }

    face_result = result["results"][0]
    confidence_for_employee = face_result["probability_distribution"].get(employee_id, 0.0)
    is_verified = (
        face_result["identified_as"] == employee_id and
        confidence_for_employee >= threshold
    )

    return {
        "verified": is_verified,
        "employee_id": employee_id,
        "confidence": confidence_for_employee,
        "threshold": threshold,
        "best_match": face_result["identified_as"],
        "best_match_confidence": face_result["confidence"],
        "full_distribution": face_result["probability_distribution"],
        "face_distances": face_result["face_distances_per_employee"],
        "timestamp": datetime.utcnow().isoformat()
    }


